import{_ as e,o as t,c as l,ag as r}from"./chunks/framework.DUza98OV.js";const h=JSON.parse('{"title":"GC 调优入门","description":"","frontmatter":{},"headers":[],"relativePath":"jvm/gc-tuning.md","filePath":"jvm/gc-tuning.md","lastUpdated":1776563785000}'),i={name:"jvm/gc-tuning.md"};function n(o,a,s,c,d,m){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="gc-调优入门" tabindex="-1">GC 调优入门 <a class="header-anchor" href="#gc-调优入门" aria-label="Permalink to &quot;GC 调优入门&quot;">​</a></h1><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>服务出现频繁 Full GC、接口 RT 飙高时，应该如何定位 JVM 垃圾回收问题？</p><h2 id="explanation" tabindex="-1">Explanation <a class="header-anchor" href="#explanation" aria-label="Permalink to &quot;Explanation&quot;">​</a></h2><p>GC 调优的第一步不是盲目改参数，而是先看对象分配模式和停顿来源。可以结合 GC 日志、堆转储和监控面板判断是新生代回收过于频繁，还是老年代对象晋升过快。常见根因包括大对象分配、缓存无法回收、线程池积压导致对象生命周期拉长等。</p><p>不同收集器的目标不同。G1 更强调可预测停顿，适合大堆低停顿场景；Parallel GC 更追求吞吐量，适合离线任务。调优时要围绕业务目标选择合适的回收器，而不是只追求“GC 次数更少”。</p><h2 id="key-points" tabindex="-1">Key Points <a class="header-anchor" href="#key-points" aria-label="Permalink to &quot;Key Points&quot;">​</a></h2><ul><li>先看日志和监控，再决定参数调整方向。</li><li>分清 Minor GC、Mixed GC 和 Full GC 的成因。</li><li>关注对象晋升、内存泄漏和大对象分配。</li><li>调优目标应该和吞吐量、延迟目标绑定。</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>GC 调优是数据驱动的工程问题。只有先搞清楚对象生命周期和内存压力来源，参数调整才有意义。</p>',10)])])}const u=e(i,[["render",n]]);export{h as __pageData,u as default};
